// Combine the row data with the EE prompt template
const row = $input.first().json;
const prompts = $('Fetch EE Prompts').all();

// Find the EE prompt
const eePrompt = prompts.find(p => p.json['Prompt Name'] === 'EE Count');
if (!eePrompt) throw new Error('EE Count prompt not found in Prompts sheet');

// Substitute company details into the prompt
let prompt = eePrompt.json['Prompt Text'];
prompt = prompt.replace('{{Primary Name}}', row['Primary Name'] || '');
prompt = prompt.replace('{{Street Address}}', row['Street Address'] || '');
prompt = prompt.replace('{{City}}', row['City'] || '');
prompt = prompt.replace('{{State}}', row['State'] || '');
prompt = prompt.replace('{{Bureau Number}}', row['Bureau Number'] || '');

return [{ json: { ...row, prompt, row_number: row['row_number'] } }];

// Parse the Perplexity response for EE count
const input = $input.first().json;
const response = input.choices?.[0]?.message?.content || input.content || '';

// Extract employee count from response
let eeCount = null;
const patterns = [
  /(?:approximately|about|around|roughly|estimated)?\s*(\d[,\d]*)\s*(?:employees|workers|staff)/i,
  /employee\s*count[:\s]*(\d[,\d]*)/i,
  /headcount[:\s]*(\d[,\d]*)/i,
  /(\d[,\d]*)\s*(?:full-time|FTE)/i,
];

for (const pattern of patterns) {
  const match = response.match(pattern);
  if (match) {
    eeCount = parseInt(match[1].replace(/,/g, ''), 10);
    break;
  }
}

// Sanity check: flag unreasonable values for human review
if (eeCount !== null && (eeCount < 1 || eeCount > 500000)) {
  eeCount = null;
}

// Flag for human review if parsing failed or value out of range
const reviewNeeded = eeCount === null ? 'REVIEW NEEDED - AI parse failed or value out of range' : '';

// Extract sources
const sources = [];
const urlPattern = /\[([^\]]+)\]\(([^)]+)\)/g;
let urlMatch;
while ((urlMatch = urlPattern.exec(response)) !== null) {
  sources.push(urlMatch[2]);
}

return [{
  json: {
    row_number: input.row_number,
    ee_count: eeCount,
    review_flag: reviewNeeded,
    ee_response: response.substring(0, 2000),
    sources: sources.join('\n'),
    'Primary Name': input['Primary Name'],
    'Bureau Number': input['Bureau Number'],
  }
}];

// Deduplicate by Bureau Number — only process each company once
const items = $input.all();
const seen = new Set();
const unique = [];

for (const item of items) {
  const key = item.json['Bureau Number'] || `${item.json['Primary Name']}|${item.json['Street Address']}`;
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(item);
  }
}

return unique;

// Build domain + FP/NP lookup prompt
const row = $input.first().json;
const prompts = $('Fetch Domain Prompts').all();

const domainPrompt = prompts.find(p => p.json['Prompt Name'] === 'Domain + FP/NP');
if (!domainPrompt) throw new Error('Domain + FP/NP prompt not found in Prompts sheet');

let prompt = domainPrompt.json['Prompt Text'];
prompt = prompt.replace('{{Primary Name}}', row['Primary Name'] || '');
prompt = prompt.replace('{{Street Address}}', row['Street Address'] || '');
prompt = prompt.replace('{{City}}', row['City'] || '');
prompt = prompt.replace('{{State}}', row['State'] || '');

return [{ json: { ...row, prompt } }];

// Parse domain and FP/NP classification from Perplexity response
const input = $input.first().json;
const response = input.choices?.[0]?.message?.content || input.content || '';

// Extract domain — prefer explicitly labeled domain/website matches first
let domain = '';
let domainConfidence = 'high';
const domainPatterns = [
  /(?:website|domain|official\s+(?:website|site)|url)[:\s]+(?:https?:\/\/)?(?:www\.)?([a-z0-9][a-z0-9-]*\.[a-z]{2,})/i,
];
for (const p of domainPatterns) {
  const m = response.match(p);
  if (m) { domain = m[1].toLowerCase(); break; }
}
// Greedy fallback — flag as low confidence
if (!domain) {
  const fallback = response.match(/(?:https?:\/\/)?(?:www\.)?([a-z0-9][a-z0-9-]*\.[a-z]{2,})/i);
  if (fallback) {
    domain = fallback[1].toLowerCase();
    domainConfidence = 'low';
  }
}

// Extract FP/NP
let fpnp = '';
if (/non[- ]?profit|501\(?c\)?/i.test(response)) fpnp = 'Non-Profit';
else if (/for[- ]?profit|commercial|private company/i.test(response)) fpnp = 'For-Profit';

// Review flag for missing data
const issues = [];
if (!domain) issues.push('domain not found');
if (!fpnp) issues.push('FP/NP not determined');
if (domainConfidence === 'low') issues.push('domain low confidence');
const reviewFlag = issues.length > 0 ? 'REVIEW NEEDED - ' + issues.join(', ') : '';

// Extract sources
const sources = [];
const urlPattern = /\[([^\]]+)\]\(([^)]+)\)/g;
let urlMatch;
while ((urlMatch = urlPattern.exec(response)) !== null) {
  sources.push(urlMatch[2]);
}

return [{
  json: {
    row_number: input.row_number,
    domain,
    fp_np: fpnp,
    review_flag: reviewFlag,
    sources: sources.join('\n'),
    'Primary Name': input['Primary Name'],
    'Bureau Number': input['Bureau Number'],
  }
}];

// After all domain lookups complete, reformat to 5 rows + blank separator per company
const items = $input.all();

// Group by company (Bureau Number or Primary Name + Address)
const groups = {};
const order = [];

for (const item of items) {
  const bn = item.json['Bureau Number'] || '';
  const name = item.json['Primary Name'] || '';
  const addr = item.json['Street Address'] || '';
  const key = bn || `${name}|${addr}`;

  if (!key) continue;

  if (!groups[key]) {
    groups[key] = [];
    order.push(key);
  }
  groups[key].push(item.json);
}

// Build reformatted output: 5 copies of first row per company + blank
const output = [];
for (const key of order) {
  const rows = groups[key];
  const template = rows[0];

  for (let i = 0; i < 5; i++) {
    output.push({ json: { ...template, _block_row: i + 1, _is_separator: false } });
  }
  // Blank separator
  output.push({ json: { _is_separator: true } });
}

return output;

// Extract LinkedIn profile URL from Apify response
const input = $input.first().json;
const results = input.data || input.items || input || [];

let liUrl = '';
if (Array.isArray(results)) {
  for (const r of results) {
    const url = r.linkedinUrl || r.profileUrl || r.url || '';
    if (url.includes('linkedin.com/in/')) {
      liUrl = url;
      break;
    }
  }
}

return [{ json: { ...input, li_profile: liUrl } }];

// Determine For-Profit vs Non-Profit to route to correct doc
const row = $input.first().json;
const fpnp = (row['For-Profit/Non-Profit'] || '').toLowerCase();

const isNonProfit = fpnp.includes('non-profit') || fpnp.includes('nonprofit');

return [{ json: { ...row, is_non_profit: isNonProfit } }];

// Parse corrected name and build label text
const input = $input.first().json;
const response = input.choices?.[0]?.message?.content || input.content || '';

// Clean the corrected name
let correctedName = response.trim().replace(/^["']|["']$/g, '').trim();
let usedFallback = false;
if (!correctedName || correctedName.length > 200) {
  correctedName = input['Primary Name']; // fallback
  usedFallback = true;
}

// Flag for review if fallback was used
const reviewFlag = usedFallback ? 'REVIEW NEEDED - corrected name fallback to original' : '';

// Build address label
const prospect = input['Prospect'] || '';
const street = input['Street Address'] || '';
const city = input['City'] || '';
const state = input['State'] || '';
const zip = input['Zip Code'] || '';

const label = `${prospect}\n${correctedName}\n${street}\n${city} ${state} ${zip}`.trim();

return [{
  json: {
    ...input,
    corrected_name: correctedName,
    corrected_name_reasoning: reviewFlag,
    label_text: label,
    combined_address: `${street}, ${city}, ${state} ${zip}`.trim(),
  }
}];

// Write label to the appropriate Google Doc
// The actual Google Docs write is done via Google Docs API node
const input = $input.first().json;
const isNP = input.is_non_profit;

return [{
  json: {
    ...input,
    doc_id: isNP ? 'NON_PROFIT_DOC_ID' : 'GENERAL_DOC_ID',
    label_number: input['Label #'] || '',
  }
}];
